import sys

class Solution:
    def checkEulerianCircuit(self, graph: list[list[int]]) -> bool:    
        degreeMap = {}    
        for vertex in graph:
            degree = len(vertex)
            degreeMap[vertex] = degree
        oddVertices = 0
        for vertex, degree in degreeMap.items():
            if degree % 2 == 1:
                oddVertices += 1
        if oddVertices == 0 or (oddVertices == 1 and sum(degreeMap.values()) % 2 == 1):
            return True
        else:
            return False

# main function
graph = [[1, 2], [0, 2], [0, 1], [3], [2, 3], [1, 3]]
sol = Solution()
print(sol.checkEulerianCircuit(graph))

