#include <bits/stdc++.h>
#include <iostream>

using namespace std;

class Solution : public SolutionBase<int> {
public:    
bool checkEulerianCircuit(vector<vector<int>>& graph) {
        int oddVertices = 0;    
        for (auto vertex : graph) {
            int degree = vertex.size();
            if (degree % 2 === 1) {
                oddVertices++;
            }
        }
        if (oddVertices === 0 || (oddVertices === 1 && graph.front().size() % 2 !== 0)) {
            return true;
        } else {
            return false;
        }
    }
};
